// Services/ReviewSanitizer.cs
using System.Net;
using System.Text.RegularExpressions;

namespace ProductReviews.Services
{
    /// <summary>
    /// Sanitizes user-submitted review content to allow only safe formatting tags (b, i, strong, em).
    /// 
    /// Security approach:
    /// 1. First, HTML-encode the entire input to neutralize ALL HTML/script injection.
    /// 2. Then, selectively re-enable only the specific safe tags we want to allow
    ///    by converting their encoded forms back to actual HTML tags.
    /// 3. Convert newlines to <br> for readability.
    /// 
    /// This whitelist approach ensures that even if an attacker tries to inject
    /// <script>, <img onerror=...>, event handlers, or any other malicious HTML,
    /// it will remain encoded and rendered as harmless text.
    /// </summary>
    public class ReviewSanitizer : IReviewSanitizer
    {
        public string SanitizeReviewContent(string rawContent)
        {
            if (string.IsNullOrEmpty(rawContent))
                return string.Empty;

            // Step 1: HTML-encode EVERYTHING. This neutralizes all potential XSS vectors.
            string encoded = WebUtility.HtmlEncode(rawContent);

            // Step 2: Whitelist - selectively re-enable ONLY safe formatting tags.
            // After encoding, tags like <b> become &lt;b&gt;
            // We convert only these specific safe patterns back to HTML tags.

            // Allow <b> and </b>
            encoded = Regex.Replace(encoded, @"&lt;b&gt;", "<b>", RegexOptions.IgnoreCase);
            encoded = Regex.Replace(encoded, @"&lt;/b&gt;", "</b>", RegexOptions.IgnoreCase);

            // Allow <i> and </i>
            encoded = Regex.Replace(encoded, @"&lt;i&gt;", "<i>", RegexOptions.IgnoreCase);
            encoded = Regex.Replace(encoded, @"&lt;/i&gt;", "</i>", RegexOptions.IgnoreCase);

            // Allow <strong> and </strong>
            encoded = Regex.Replace(encoded, @"&lt;strong&gt;", "<strong>", RegexOptions.IgnoreCase);
            encoded = Regex.Replace(encoded, @"&lt;/strong&gt;", "</strong>", RegexOptions.IgnoreCase);

            // Allow <em> and </em>
            encoded = Regex.Replace(encoded, @"&lt;em&gt;", "<em>", RegexOptions.IgnoreCase);
            encoded = Regex.Replace(encoded, @"&lt;/em&gt;", "</em>", RegexOptions.IgnoreCase);

            // Step 3: Convert newlines to <br> for display
            encoded = encoded.Replace("\r\n", "<br>").Replace("\n", "<br>").Replace("\r", "<br>");

            // Step 4: Ensure balanced tags by closing any unclosed allowed tags
            // This prevents tag injection across review boundaries
            encoded = EnsureBalancedTags(encoded);

            return encoded;
        }

        private string EnsureBalancedTags(string html)
        {
            string[] allowedTags = { "b", "i", "strong", "em" };

            foreach (var tag in allowedTags)
            {
                int openCount = Regex.Matches(html, $"<{tag}>", RegexOptions.IgnoreCase).Count;
                int closeCount = Regex.Matches(html, $"</{tag}>", RegexOptions.IgnoreCase).Count;

                // Close any unclosed tags
                while (openCount > closeCount)
                {
                    html += $"</{tag}>";
                    closeCount++;
                }

                // Remove extra closing tags
                while (closeCount > openCount)
                {
                    int lastIndex = html.LastIndexOf($"</{tag}>", System.StringComparison.OrdinalIgnoreCase);
                    if (lastIndex >= 0)
                    {
                        html = html.Remove(lastIndex, $"</{tag}>".Length);
                        closeCount--;
                    }
                    else
                    {
                        break;
                    }
                }
            }

            return html;
        }
    }
}

// Controllers/ProductController.cs
using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ProductReviews.Data;
using ProductReviews.Models;
using ProductReviews.Services;

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;
        private readonly IReviewSanitizer _reviewSanitizer;

        public ProductController(ApplicationDbContext context, IReviewSanitizer reviewSanitizer)
        {
            _context = context;
            _reviewSanitizer = reviewSanitizer;
        }

        // GET: /Product/Details/5
        public async Task<IActionResult> Details(int? id)
        {
            if (id == null)
                return NotFound();

            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
                return NotFound();

            var viewModel = new ProductViewModel
            {
                Product = product,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAt)
                    .Select(r => new ReviewViewModel
                    {
                        Id = r.Id,
                        // AuthorName is always HTML-encoded in the view via @Model syntax (no Html.Raw)
                        AuthorName = r.AuthorName,
                        // Content is sanitized: all HTML encoded first, then only safe tags whitelisted
                        SanitizedHtmlContent = _reviewSanitizer.SanitizeReviewContent(r.Content),
                        Rating = r.Rating,
                        CreatedAt = r.CreatedAt.ToString("MMMM dd, yyyy 'at' h:mm tt")
                    })
                    .ToList(),
                NewReview = new ReviewSubmitModel { ProductId = id.Value }
            };

            return View(viewModel);
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> SubmitReview(ReviewSubmitModel model)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction(nameof(Details), new { id = model.ProductId });
            }

            var product = await _context.Products.FindAsync(model.ProductId);
            if (product == null)
                return NotFound();

            var review = new Review
            {
                ProductId = model.ProductId,
                AuthorName = model.AuthorName,
                Content = model.Content, // Stored raw; sanitized on output
                Rating = model.Rating,
                CreatedAt = DateTime.UtcNow
            };

            _context.Reviews.Add(review);
            await _context.SaveChangesAsync();

            return RedirectToAction(nameof(Details), new { id = model.ProductId });
        }
    }
}

