// Tests/ReviewSanitizerTests.cs
using ProductReviews.Services;
using Xunit;

namespace ProductReviews.Tests
{
    public class ReviewSanitizerTests
    {
        private readonly ReviewSanitizer _sanitizer = new ReviewSanitizer();

        [Fact]
        public void SanitizeReviewContent_ScriptTag_IsEncoded()
        {
            var input = "<script>alert('xss')</script>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.DoesNotContain("<script>", result);
            Assert.Contains("&lt;script&gt;", result);
        }

        [Fact]
        public void SanitizeReviewContent_AllowsBoldTag()
        {
            var input = "This is <b>bold</b> text";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<b>bold</b>", result);
        }

        [Fact]
        public void SanitizeReviewContent_AllowsItalicTag()
        {
            var input = "This is <i>italic</i> text";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<i>italic</i>", result);
        }

        [Fact]
        public void SanitizeReviewContent_AllowsStrongTag()
        {
            var input = "This is <strong>strong</strong> text";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<strong>strong</strong>", result);
        }

        [Fact]
        public void SanitizeReviewContent_AllowsEmTag()
        {
            var input = "This is <em>emphasized</em> text";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<em>emphasized</em>", result);
        }

        [Fact]
        public void SanitizeReviewContent_BlocksImgTag()
        {
            var input = "<img src=x onerror=alert('xss')>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.DoesNotContain("<img", result);
        }

        [Fact]
        public void SanitizeReviewContent_BlocksOnEventAttributes()
        {
            var input = "<b onmouseover=alert('xss')>text</b>";
            var result = _sanitizer.SanitizeReviewContent(input);
            // The <b onmouseover=...> gets fully encoded because it doesn't match
            // the exact pattern &lt;b&gt; (it has attributes)
            Assert.DoesNotContain("onmouseover", result.ToLower().Replace("&", ""));
        }

        [Fact]
        public void SanitizeReviewContent_BlocksAnchorTag()
        {
            var input = "<a href='javascript:alert(1)'>click</a>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.DoesNotContain("<a ", result);
            Assert.DoesNotContain("javascript:", result);
        }

        [Fact]
        public void SanitizeReviewContent_BlocksIframeTag()
        {
            var input = "<iframe src='https://evil.com'></iframe>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.DoesNotContain("<iframe", result);
        }

        [Fact]
        public void SanitizeReviewContent_HandlesNestedMaliciousContent()
        {
            var input = "<b><script>alert('xss')</script></b>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<b>", result);
            Assert.Contains("</b>", result);
            Assert.DoesNotContain("<script>", result);
        }

        [Fact]
        public void SanitizeReviewContent_HandlesNullInput()
        {
            var result = _sanitizer.SanitizeReviewContent(null);
            Assert.Equal(string.Empty, result);
        }

        [Fact]
        public void SanitizeReviewContent_HandlesEmptyInput()
        {
            var result = _sanitizer.SanitizeReviewContent("");
            Assert.Equal(string.Empty, result);
        }

        [Fact]
        public void SanitizeReviewContent_ConvertsNewlinesToBr()
        {
            var input = "Line 1\nLine 2";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("<br>", result);
        }

        [Fact]
        public void SanitizeReviewContent_BlocksBoldWithAttributes()
        {
            // <b style="..."> should NOT be allowed - only plain <b>
            var input = "<b style=\"color:red\">text</b>";
            var result = _sanitizer.SanitizeReviewContent(input);
            // The tag with attributes gets encoded, not rendered as HTML
            Assert.DoesNotContain("style=", result);
        }

        [Fact]
        public void SanitizeReviewContent_BalancesUnclosedTags()
        {
            var input = "<b>unclosed bold";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.Contains("</b>", result);
        }

        [Fact]
        public void SanitizeReviewContent_BlocksSvgOnload()
        {
            var input = "<svg onload=alert('xss')>";
            var result = _sanitizer.SanitizeReviewContent(input);
            Assert.DoesNotContain("<svg", result);
            Assert.DoesNotContain("onload", result.Replace("&", "").Replace("lt;", "<").Replace("gt;", ">"));
        }
    }
}